/* ============================================================
   TerminalSync — Rediseño compacto
   Two variations toggled by a class on <html>:
   .var-phosphor (A)  ·  .var-spectrum (B)
   ============================================================ */

@import url('https://fonts.googleapis.com/css2?family=Geist:wght@400;500;600;700&family=Geist+Mono:wght@400;500;600&display=swap');

/* ---------- Base tokens (shared) ---------- */
:root {
  --bg:        #08090b;
  --bg-2:      #0c0e12;
  --surface:   #111419;
  --surface-2: #161a20;
  --line:      rgba(255,255,255,0.08);
  --line-2:    rgba(255,255,255,0.14);

  --fg:        #f3f5f7;
  --fg-2:      #aab2bd;
  --fg-3:      #6b727d;

  --claude:    #d97757;
  --codex:     #2dd4a7;
  --gemini:    #5b9cff;

  /* accent is overridden per variation */
  --accent:    #46e6a4;
  --accent-2:  #2dd4a7;
  --accent-ink:#04130d;
  --glow:      transparent;

  --sans: 'Geist', system-ui, -apple-system, sans-serif; /* @kind font */
  --mono: 'Geist Mono', ui-monospace, 'SF Mono', Menlo, monospace; /* @kind font */

  --r-sm: 8px;
  --r:    14px;
  --r-lg: 22px;

  --maxw: 1140px;
  --gut:  clamp(20px, 5vw, 40px); /* @kind spacing */

  --ease: cubic-bezier(.22,.61,.36,1); /* @kind other */
}

/* ---------- Dark theme (terminal · green accent) ---------- */
.var-dark {
  --accent:   #4fe9a6;
  --accent-2: #34d399;
  --accent-ink: #04130d;
  --glow: transparent;
}

/* ---------- Light theme (warm paper · emerald accent) — DEFAULT ----------
   Business-friendly surface; product/terminal mocks stay dark (scoped below). */
.var-light {
  --bg:        #f7f5f1;
  --bg-2:      #fffefb;
  --surface:   #ffffff;
  --surface-2: #faf8f4;
  --line:      rgba(24,26,31,0.10);
  --line-2:    rgba(24,26,31,0.16);

  --fg:        #16181d;
  --fg-2:      #565b64;
  --fg-3:      #8b909a;

  --accent:    #0f9d6e;
  --accent-2:  #0b8a5f;
  --accent-ink:#ffffff;
  --glow:      rgba(15,157,110,0.14);
}

/* Spectrum kept for reference; not exposed in the switch */
.var-spectrum {
  --accent:   #7c8cff;
  --accent-2: #5b9cff;
  --accent-ink: #060814;
  --glow: rgba(124,140,255,0.16);
  --surface:   #12131b;
  --surface-2: #181a25;
}

/* ============================================================
   Reset
   ============================================================ */
*, *::before, *::after { box-sizing: border-box; }
html { scroll-behavior: smooth; -webkit-text-size-adjust: 100%; }
body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-family: var(--sans);
  font-size: 17px;
  line-height: 1.6;
  letter-spacing: -0.01em;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}
a { color: inherit; text-decoration: none; }
img, svg { display: block; max-width: 100%; }
button { font-family: inherit; cursor: pointer; border: none; background: none; color: inherit; }
h1, h2, h3, h4 { margin: 0; font-weight: 600; letter-spacing: -0.03em; line-height: 1.08; }
p { margin: 0; }
::selection { background: var(--accent); color: var(--accent-ink); }

/* ============================================================
   Layout helpers
   ============================================================ */
.wrap { max-width: var(--maxw); margin: 0 auto; padding-inline: var(--gut); }
.section { padding-block: clamp(64px, 9vw, 120px); position: relative; }
.section--tight { padding-block: clamp(44px, 6vw, 72px); }

.eyebrow {
  font-family: var(--mono);
  font-size: 12.5px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--accent);
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 8px;
}
.eyebrow::before {
  content: "";
  width: 6px; height: 6px; border-radius: 2px;
  background: var(--accent);
  box-shadow: 0 0 10px var(--accent);
}

.h-section {
  font-size: clamp(28px, 4.2vw, 46px);
  letter-spacing: -0.035em;
  line-height: 1.12;
  margin-top: 18px;
  max-width: 18ch;
  padding-bottom: 0.08em;
}
.sub-section {
  color: var(--fg-2);
  font-size: clamp(16px, 1.6vw, 19px);
  margin-top: 16px;
  max-width: 56ch;
}
.section-head { margin-bottom: clamp(36px, 5vw, 56px); }
.center { text-align: center; }
.center .h-section, .center .sub-section { margin-inline: auto; }

/* ============================================================
   Buttons
   ============================================================ */
.btn {
  display: inline-flex; align-items: center; gap: 9px;
  padding: 13px 22px;
  border-radius: 999px;
  font-weight: 500;
  font-size: 15.5px;
  letter-spacing: -0.01em;
  transition: transform .18s var(--ease), background .2s, border-color .2s, box-shadow .25s;
  white-space: nowrap;
}
.btn:active { transform: scale(.97); }
.btn-primary {
  background: var(--accent);
  color: var(--accent-ink);
  font-weight: 600;
  box-shadow: 0 8px 30px -10px var(--accent);
}
.btn-primary:hover { box-shadow: 0 10px 40px -8px var(--accent); transform: translateY(-1px); }
.btn-ghost {
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--line-2);
  color: var(--fg);
}
.btn-ghost:hover { background: rgba(255,255,255,0.08); border-color: rgba(255,255,255,0.22); }
.btn-sm { padding: 10px 16px; font-size: 14px; }

.link-arrow {
  display: inline-flex; align-items: center; gap: 7px;
  color: var(--fg); font-weight: 500; font-size: 15px;
}
.link-arrow .ar { transition: transform .2s var(--ease); color: var(--accent); }
.link-arrow:hover .ar { transform: translateX(4px); }

/* ============================================================
   Nav
   ============================================================ */
.nav {
  position: sticky; top: 0; z-index: 80;
  backdrop-filter: blur(14px);
  background: color-mix(in srgb, var(--bg) 78%, transparent);
  border-bottom: 1px solid transparent;
  transition: border-color .3s, background .3s;
}
.nav.scrolled { border-bottom-color: var(--line); }
.nav-inner {
  max-width: var(--maxw); margin: 0 auto; padding: 14px var(--gut);
  display: flex; align-items: center; gap: 28px;
}
