"use client";

import { useState, useEffect } from "react";
import { ArrowRight, Shield, Check } from "lucide-react";
import type { Dict } from "@/content";
import { ClaudeMark, OpenAIMark, GeminiMark } from "@/components/brand/AILogos";
import { WindowsEarlyAccess } from "./WindowsEarlyAccess";

// Rotating headline phrases — ES
const PHRASES_ES: string[] = [
  'Convierte tus ideas en <span class="grad">herramientas reales</span> hablando con tus IAs.',
  'Tu primer <span class="grad">equipo digital.</span> Construye sistemas hablando.',
  'Describe el problema. <span class="grad">Tus IAs construyen la solución.</span>',
  '¿Por qué conformarte con <span class="grad">una sola IA</span>?',
  'Claude, Codex y Gemini. <span class="grad">Una sola memoria.</span>',
  'La forma más fácil de <span class="grad">crear software para tu negocio.</span>',
  'Tu oficina cabe en <span class="grad">cualquier computadora.</span>',
  '<span class="grad">Multiplica tu capacidad</span> sin multiplicar tu nómina.',
  'No sincronizamos archivos. <span class="grad">Sincronizamos continuidad.</span>',
];

// Rotating headline phrases — EN
const PHRASES_EN: string[] = [
  'Turn your ideas into <span class="grad">real tools</span> by talking to your AIs.',
  'Your first <span class="grad">digital team.</span> Build systems by talking.',
  'Describe the problem. <span class="grad">Your AIs build the solution.</span>',
  'Why settle for <span class="grad">a single AI</span>?',
  'Claude, Codex and Gemini. <span class="grad">One shared memory.</span>',
  'The easiest way to <span class="grad">create software for your business.</span>',
  'Your office fits in <span class="grad">any computer.</span>',
  '<span class="grad">Multiply your capacity</span> without multiplying your payroll.',
  'We don\'t sync files. <span class="grad">We sync continuity.</span>',
];

const ROTATION_INTERVAL = 6500;

export function Hero({ dict }: { dict: Dict }) {
  const isEs = dict.locale === "es";
  const phrases = isEs ? PHRASES_ES : PHRASES_EN;

  const [index, setIndex] = useState(0);
  const [visible, setVisible] = useState(true);
  const [prefersReduced, setPrefersReduced] = useState(false);

  useEffect(() => {
    const mq = window.matchMedia("(prefers-reduced-motion: reduce)");
    setPrefersReduced(mq.matches);
    const handler = (e: MediaQueryListEvent) => setPrefersReduced(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);

  useEffect(() => {
    if (prefersReduced) return;
    const id = setInterval(() => {
      setVisible(false);
      setTimeout(() => {
        setIndex((i) => (i + 1) % phrases.length);
        setVisible(true);
      }, 400);
    }, ROTATION_INTERVAL);
    return () => clearInterval(id);
  }, [prefersReduced, phrases.length]);

  const gradStyle: React.CSSProperties = {
    background:
      "linear-gradient(135deg, var(--color-accent), var(--color-accent-soft))",
    WebkitBackgroundClip: "text",
    WebkitTextFillColor: "transparent",
    backgroundClip: "text",
  };

  // Trust chips
  const chips = isEs
    ? [
        { icon: <Check size={12} strokeWidth={2.5} />, label: "Claude · Codex · Gemini incluidas" },
        { icon: <Check size={12} strokeWidth={2.5} />, label: "Listo en minutos" },
        { icon: <Shield size={12} strokeWidth={2.5} />, label: "Cifrado E2EE · ni nosotros lo leemos" },
      ]
    : [

