"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";

interface Props {
  lang: string;
}

export function CatalogNav({ lang }: Props) {
  const pathname = usePathname();

  return (
    <nav className="cat-tabs-wrap" aria-label="Categorías del catálogo">
      <div className="wrap">
        <div className="cat-tabs">
          <Link
            href={`/${lang}/stacks`}
